1	// meta-gen -- Generate .meta files for link24
2	//
3	// Two-phase tool for preparing modules for separate compilation:
4	//
5	// Phase 1 (prep): Reads a .s file, identifies labels defined locally
6	//   and references to external symbols. Rewrites external `la rN,<sym>`
7	//   to `la rN,0` (assembleable placeholder). Writes modified .s and a
8	//   .syms file listing external references and their source lines.
9	//
10	// Phase 2 (emit): After assembly, reads the .lst file and .syms file
11	//   to produce the final .meta with byte-accurate EXPORT and FIXUP offsets.
12	//
13	// Usage:
14	//   meta-gen prep <input.s> -o <output.s> [--syms <output.syms>]
15	//   meta-gen emit <input.lst> --syms <input.syms> --module <name> -o <output.meta>
16	
17	use std::collections::{HashMap, HashSet};
18	use std::fs;
19	use std::io::Write;
20	use std::process;
21	
22	fn die(msg: &str) -> ! {
23	    eprintln!("meta-gen: error: {}", msg);
24	    process::exit(1);
25	}
26	
27	// --- Phase 1: prep ---
28	
29	fn cmd_prep(input: &str, output: &str, syms_path: &str) {
30	    let content = fs::read_to_string(input)
31	        .unwrap_or_else(|e| die(&format!("cannot read {}: {}", input, e)));
32	
33	    // Pass 1: collect all labels defined in this file
34	    let mut defined: HashSet<String> = HashSet::new();
35	    for line in content.lines() {
36	        let trimmed = line.trim();
37	        // Label definition: starts at column 0, ends with ':'
38	        if !trimmed.is_empty()
39	            && !trimmed.starts_with(' ')
40	            && !trimmed.starts_with('\t')
41	            && !trimmed.starts_with(';')
42	            && !trimmed.starts_with('.')
43	        {
44	            if let Some(label) = trimmed.strip_suffix(':') {
45	                defined.insert(label.to_string());
46	            }
47	        }
48	    }
49	
50	    // Pass 2: find external references and rewrite
51	    let mut out_lines: Vec<String> = Vec::new();
52	    let mut extern_refs: Vec<(usize, String)> = Vec::new(); // (line_num, symbol)
53	
54	    for (line_num, line) in content.lines().enumerate() {
55	        let trimmed = line.trim();
56	
57	        // Match: la rN,<symbol> where <symbol> starts with _
58	        // Patterns: "la r0,_SYM", "la r2,_SYM", "la r1,_SYM"
59	        if let Some(la_match) = parse_la_external(trimmed, &defined) {
60	            extern_refs.push((line_num + 1, la_match.symbol.clone()));
61	            // Rewrite to la rN,0
62	            let new_line = line.replace(
63	                &format!(",{}", la_match.symbol),
64	                ",0",
65	            );
66	            out_lines.push(new_line);
67	        } else {
68	            out_lines.push(line.to_string());
69	        }
70	    }
71	
72	    // Write modified .s
73	    let mut f = fs::File::create(output)
74	        .unwrap_or_else(|e| die(&format!("cannot create {}: {}", output, e)));
75	    for line in &out_lines {
76	        writeln!(f, "{}", line).unwrap();
77	    }
78	
79	    // Write .syms (external references with source line numbers)
80	    let mut sf = fs::File::create(syms_path)
81	        .unwrap_or_else(|e| die(&format!("cannot create {}: {}", syms_path, e)));
82	    // Header: defined labels (for reference)
83	    writeln!(sf, "; Defined labels in this module").unwrap();
84	    let mut sorted_defined: Vec<&String> = defined.iter().collect();
85	    sorted_defined.sort();
86	    for label in &sorted_defined {
87	        writeln!(sf, "DEF {}", label).unwrap();
88	    }
89	    writeln!(sf, "; External references (source_line symbol)").unwrap();
90	    for (line_num, sym) in &extern_refs {
91	        writeln!(sf, "REF {} {}", line_num, sym).unwrap();
92	    }
93	
94	    eprintln!(
95	        "meta-gen: prep {} -> {} ({} defined, {} external refs)",
96	        input, output, defined.len(), extern_refs.len()
97	    );
98	}
99	
100	struct LaMatch {
101	    symbol: String,
102	}
103	
104	fn parse_la_external(line: &str, defined: &HashSet<String>) -> Option<LaMatch> {
105	    // Match "la rN,_SYMBOL" where _SYMBOL is not defined locally
106	    let line = line.trim();
107	    if !line.starts_with("la ") {
108	        return None;
109	    }
110	    let rest = line[3..].trim();
111	    // rest is "rN,_SYMBOL" or "rN,number" etc.
112	    let comma = rest.find(',')?;
113	    let target = rest[comma + 1..].trim();
114	
115	    // Only external symbols: must start with _ and be uppercase
116	    if !target.starts_with('_') {
117	        return None;
118	    }
119	    // Must be a symbol name (not a number)
120	    if target.chars().nth(1).map_or(true, |c| !c.is_ascii_alphabetic()) {
121	        return None;
122	    }
123	
124	    let symbol = target.to_string();
125	    if defined.contains(&symbol) {
126	        return None; // Local -- not external
127	    }
128	
129	    Some(LaMatch { symbol })
130	}
131	
132	// --- Phase 2: emit ---
133	
134	fn cmd_emit(lst_path: &str, syms_path: &str, module_name: &str, output: &str) {
135	    let lst_content = fs::read_to_string(lst_path)
136	        .unwrap_or_else(|e| die(&format!("cannot read {}: {}", lst_path, e)));
137	    let syms_content = fs::read_to_string(syms_path)
138	        .unwrap_or_else(|e| die(&format!("cannot read {}: {}", syms_path, e)));
139	
140	    // Parse .syms: collect defined labels and external references
141	    let mut defined_labels: HashSet<String> = HashSet::new();
142	    let mut ext_refs: Vec<(usize, String)> = Vec::new(); // (source_line, symbol)
143	
144	    for line in syms_content.lines() {
145	        let line = line.trim();
146	        if line.starts_with(';') || line.is_empty() {
147	            continue;
148	        }
149	        let parts: Vec<&str> = line.split_whitespace().collect();
150	        if parts.len() >= 2 && parts[0] == "DEF" {
151	            defined_labels.insert(parts[1].to_string());
152	        } else if parts.len() >= 3 && parts[0] == "REF" {
153	            let line_num: usize = parts[1].parse().unwrap_or(0);
154	            ext_refs.push((line_num, parts[2].to_string()));
155	        }
156	    }
157	
158	    // Parse .lst: build label->offset map and find la instructions at offset 0
159	    // (these are the rewritten external refs)
160	    let mut label_offsets: HashMap<String, u32> = HashMap::new();
161	    let mut la_zero_offsets: Vec<u32> = Vec::new(); // byte offsets of "la rN,0" instructions
162	
163	    for line in lst_content.lines() {
164	        let trimmed = line.trim();
165	
166	        // Label definition line: just "labelname:" with no hex prefix
167	        if !trimmed.is_empty()
168	            && !trimmed.starts_with(|c: char| c.is_ascii_hexdigit())
169	            && trimmed.ends_with(':')
170	        {
171	            let label = &trimmed[..trimmed.len() - 1];
172	            // The NEXT line with a hex address gives the offset
173	            // Actually, labels in .lst appear on their own line, then the
174	            // next instruction line has the offset. We handle this below.
175	            // For now, record that we saw a label -- we'll get its offset
176	            // from the next instruction line.
177	            label_offsets.insert(label.to_string(), 0xFFFFFF); // placeholder
178	            continue;
179	        }
180	
181	        // Instruction line: "XXXX: YY ..." where XXXX is hex offset
182	        if let Some(colon_pos) = trimmed.find(':') {
183	            let hex = &trimmed[..colon_pos];
184	            if let Ok(offset) = u32::from_str_radix(hex.trim(), 16) {
185	                // Update any pending label to this offset
186	                for (_, v) in label_offsets.iter_mut() {
187	                    if *v == 0xFFFFFF {
188	                        *v = offset;
189	                    }
190	                }
191	
192	                // Check if this is an "la rN,0" (rewritten external ref)
193	                // la opcodes: r0=0x29, r1=0x2A, r2=0x2B
194	                // "la rN,0" assembles as: [opcode] 00 00 00
195	                let after_colon = trimmed[colon_pos + 1..].trim();
196	                // Format: "29 00 00 00    la      r0,0"
197	                if after_colon.len() >= 11 {
198	                    let bytes_part = &after_colon[..11]; // "XX 00 00 00"
199	                    if (bytes_part.starts_with("29") ||
200	                        bytes_part.starts_with("2A") ||
201	                        bytes_part.starts_with("2a") ||
202	                        bytes_part.starts_with("2B") ||
203	                        bytes_part.starts_with("2b"))
204	                        && bytes_part.ends_with("00 00 00")
205	                    {
206	                        // Verify it's "la rN,0" in the disassembly part
207	                        if after_colon.contains("la ") && after_colon.contains(",0") {
208	                            la_zero_offsets.push(offset);
209	                        }
210	                    }
211	                }
212	            }
213	        }
214	    }
215	
216	    // Match la-zero instructions to external references (by order)
217	    // The prep phase replaced external refs in source order,
218	    // and they appear in the same order in the listing.
219	    if la_zero_offsets.len() != ext_refs.len() {
220	        eprintln!(
221	            "meta-gen: warning: {} la-zero instructions but {} external refs in .syms",
222	            la_zero_offsets.len(), ext_refs.len()
223	        );
224	        eprintln!("  la-zero offsets: {:?}", la_zero_offsets.iter().map(|o| format!("0x{:04X}", o)).collect::<Vec<_>>());
225	        if la_zero_offsets.len() < ext_refs.len() {
226	            die("fewer la-zero instructions than external refs -- assembly may have failed");
227	        }
228	    }
229	
230	    // Write .meta
231	    let mut f = fs::File::create(output)
232	        .unwrap_or_else(|e| die(&format!("cannot create {}: {}", output, e)));
233	
234	    writeln!(f, "; {}.meta -- generated by meta-gen", module_name).unwrap();
235	    writeln!(f, "MODULE {}", module_name).unwrap();
236	    writeln!(f).unwrap();
237	
238	    // Exports: labels that start with _ AND are in the .syms DEF list.
239	    // Labels in the .lst but not in DEF are internal (e.g. __plsw_div
240	    // referenced but not defined in LIBRARY modules) (#41).
241	    let mut exports: Vec<(&String, u32)> = label_offsets.iter()
242	        .filter(|(name, offset)| {
243	            name.starts_with('_')
244	                && **offset != 0xFFFFFF
245	                && defined_labels.contains(*name)
246	        })
247	        .map(|(name, offset)| (name, *offset))
248	        .collect();
249	    exports.sort_by_key(|e| e.1);
250	
251	    for (sym, offset) in &exports {
252	        writeln!(f, "EXPORT {} 0x{:04X}", sym, offset).unwrap();
253	    }
254	
255	    if !ext_refs.is_empty() {
256	        writeln!(f).unwrap();
257	    }
258	
259	    // Fixups: match external refs to la-zero offsets
260	    let fixup_count = ext_refs.len().min(la_zero_offsets.len());
261	    for i in 0..fixup_count {
262	        writeln!(f, "FIXUP 0x{:04X} {}", la_zero_offsets[i], ext_refs[i].1).unwrap();
263	    }
264	
265	    eprintln!(
266	        "meta-gen: emit {} -> {} ({} exports, {} fixups)",
267	        lst_path, output, exports.len(), fixup_count
268	    );
269	}
270	
271	// --- CLI ---
272	
273	fn main() {
274	    let args: Vec<String> = std::env::args().collect();
275	
276	    if args.len() < 2 || args.iter().any(|a| a == "-h" || a == "--help") {
277	        eprintln!("meta-gen -- Generate .meta files for link24");
278	        eprintln!();
279	        eprintln!("Usage:");
280	        eprintln!("  meta-gen prep <input.s> -o <output.s> [--syms <output.syms>]");
281	        eprintln!("  meta-gen emit <input.lst> --syms <input.syms> --module <name> -o <output.meta>");
282	        eprintln!();
283	        eprintln!("Phase 1 (prep): Rewrites external la references to la rN,0");
284	        eprintln!("  placeholders. Writes .syms file listing external symbols.");
285	        eprintln!();
286	        eprintln!("Phase 2 (emit): Reads .lst + .syms to produce .meta with");
287	        eprintln!("  byte-accurate EXPORT and FIXUP entries for link24.");
288	        process::exit(0);
289	    }
290	
291	    match args[1].as_str() {
292	        "prep" => {
293	            let mut input = String::new();
294	            let mut output = String::new();
295	            let mut syms = String::new();
296	
297	            let mut i = 2;
298	            while i < args.len() {
299	                match args[i].as_str() {
300	                    "-o" => { i += 1; output = args.get(i).cloned().unwrap_or_default(); }
301	                    "--syms" => { i += 1; syms = args.get(i).cloned().unwrap_or_default(); }
302	                    _ if input.is_empty() => { input = args[i].clone(); }
303	                    _ => die(&format!("unexpected argument '{}'", args[i])),
304	                }
305	                i += 1;
306	            }
307	
308	            if input.is_empty() { die("prep: input .s file required"); }
309	            if output.is_empty() { die("prep: -o <output.s> required"); }
310	            if syms.is_empty() {
311	                syms = output.replace(".s", ".syms");
312	            }
313	
314	            cmd_prep(&input, &output, &syms);
315	        }
316	        "emit" => {
317	            let mut lst = String::new();
318	            let mut syms = String::new();
319	            let mut module_name = String::new();
320	            let mut output = String::new();
321	
322	            let mut i = 2;
323	            while i < args.len() {
324	                match args[i].as_str() {
325	                    "--syms" => { i += 1; syms = args.get(i).cloned().unwrap_or_default(); }
326	                    "--module" => { i += 1; module_name = args.get(i).cloned().unwrap_or_default(); }
327	                    "-o" => { i += 1; output = args.get(i).cloned().unwrap_or_default(); }
328	                    _ if lst.is_empty() => { lst = args[i].clone(); }
329	                    _ => die(&format!("unexpected argument '{}'", args[i])),
330	                }
331	                i += 1;
332	            }
333	
334	            if lst.is_empty() { die("emit: input .lst file required"); }
335	            if syms.is_empty() { die("emit: --syms required"); }
336	            if module_name.is_empty() { die("emit: --module required"); }
337	            if output.is_empty() { die("emit: -o <output.meta> required"); }
338	
339	            cmd_emit(&lst, &syms, &module_name, &output);
340	        }
341	        cmd => die(&format!("unknown command '{}' (use 'prep' or 'emit')", cmd)),
342	    }
343	}
